code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Statistic, icon } from 'decantr/components';
import { Sparkline } from 'decantr/chart';

code.example:
function KpiGridSparkline() {
  const { div, h2 } = tags;
  const metrics = [
    { label: 'Revenue', value: 1248500, prefix: '$', trend: 'up', trendValue: '+12.5%', spark: [42, 48, 51, 45, 62, 58, 72] },
    { label: 'Users', value: 84230, trend: 'up', trendValue: '+8.1%', spark: [320, 340, 310, 380, 420, 450, 480] },
    { label: 'Orders', value: 6420, trend: 'down', trendValue: '-2.3%', spark: [180, 175, 190, 165, 155, 160, 148] },
    { label: 'Conversion', value: 3.24, suffix: '%', trend: 'up', trendValue: '+0.5%', spark: [2.8, 2.9, 3.0, 3.1, 3.0, 3.2, 3.24] }
  ];
  return div({ class: css('_flex _col _gap4') },
    h2({ class: css('_heading4') }, 'Key Metrics'),
    div({ class: css('_grid _gc1 _sm:gc2 _lg:gc4 _gap4') },
      ...metrics.map(m =>
        div({ class: css('_flex _col _gap2') },
          Statistic({ label: m.label, value: m.value, prefix: m.prefix, suffix: m.suffix, trend: m.trend, trendValue: m.trendValue }),
          Sparkline({ data: m.spark, height: 32, color: m.trend === 'up' ? 'success' : 'error' })
        )
      )
    )
  );
}

